// ------------------------------------------------------------------
// MOVIE CARD COMPONENT (Single Card)
// ------------------------------------------------------------------
const MovieCard = ({ movie }) => (
  <div className="bg-[#0f172a] rounded-xl overflow-hidden shadow-lg border border-blue-900/50 hover:border-blue-400 transition-all duration-300 transform hover:scale-[1.03]">
    {/* Poster Image (Mock) */}
    <div className="h-60 w-full bg-gray-700/50 flex items-center justify-center relative">
      {/* <Film className="w-12 h-12 text-gray-400 absolute" /> */}
      <span w-full className="text-sm text-gray-400  truncate">
        <img className="w-full h-60 " src={movie.poster} alt="" />
      </span>
      {/* Real-world: Use <img src={movie.posterUrl} alt={movie.title} className="w-full h-full object-cover" /> */}
    </div>

    <div className="p-4">
      {/* Title */}
      <h3 className="text-xl font-bold text-white mb-2 truncate">
        {movie.title}
      </h3>

      {/* Details Grid */}
      <div className="text-sm grid grid-cols-2 gap-y-2 gap-x-4 text-gray-400">
        {/* Genre */}
        <p className="flex items-center gap-2">
          <Film className="w-4 h-4 text-pink-400" />
          <span className="font-medium text-pink-200">{movie.genre}</span>
        </p>

        {/* Rating */}
        <p className="flex items-center gap-2">
          <Star className="w-4 h-4 text-yellow-400" />
          <span className="font-medium text-yellow-200">
            {movie.rating} / 5
          </span>
        </p>

        {/* Release Date */}
        <p className="flex items-center gap-2">
          <Calendar className="w-4 h-4 text-blue-400" />
          <span className="font-medium">{movie.releaseDate}</span>
        </p>

        {/* Language */}
        <p className="flex items-center gap-2">
          <Languages className="w-4 h-4 text-green-400" />
          <span className="font-medium">{movie.language}</span>
        </p>
      </div>

      {/* Button */}
      {/* <button className="mt-4 w-full bg-blue-600 hover:bg-blue-700 text-white py-2 rounded-lg font-semibold transition">
        View Details
      </button> */}
    </div>
  </div>
);

